import{_ as e,o as r,c as a,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"💡 光通訊追蹤日報 — 2026年6月6日（週六）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_20260606.md","filePath":"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_20260606.md"}'),n={name:"Deep32Q知識庫/產業洞察/光通訊研究/追蹤日誌/光通訊追蹤_20260606.md"};function i(s,t,o,d,c,h){return r(),a("div",null,[...t[0]||(t[0]=[l('<h1 id="💡-光通訊追蹤日報-—-2026年6月6日-週六" tabindex="-1">💡 光通訊追蹤日報 — 2026年6月6日（週六） <a class="header-anchor" href="#💡-光通訊追蹤日報-—-2026年6月6日-週六" aria-label="Permalink to &quot;💡 光通訊追蹤日報 — 2026年6月6日（週六）&quot;">​</a></h1><blockquote><p><strong>查詢時間</strong>：TST 05:00 (2026-06-05 21:00 UTC) <strong>昨日敘事延續</strong>：COMPUTEX 6/2-5 圓滿落幕 + NVIDIA CPO 正式出貨 + Broadcom Q2 財報超預期 + TSMC CEO 警告供不應求</p></blockquote><hr><h2 id="🔴-即時指標-每日掃描" tabindex="-1">🔴 即時指標（每日掃描） <a class="header-anchor" href="#🔴-即時指標-每日掃描" aria-label="Permalink to &quot;🔴 即時指標（每日掃描）&quot;">​</a></h2><h3 id="指標1️⃣-輝達-nvidia-—-🟢-spectrum-x-cpo-正式出貨-銅退光進加速" tabindex="-1">指標1️⃣ 輝達 NVIDIA — 🟢 Spectrum-X CPO 正式出貨，銅退光進加速 <a class="header-anchor" href="#指標1️⃣-輝達-nvidia-—-🟢-spectrum-x-cpo-正式出貨-銅退光進加速" aria-label="Permalink to &quot;指標1️⃣ 輝達 NVIDIA — 🟢 Spectrum-X CPO 正式出貨，銅退光進加速&quot;">​</a></h3><ul><li><strong>最新動態（6/5 COMPUTEX 最後一天）</strong>： <ul><li><strong>Spectrum-X CPO 交換器</strong>：400Tb/s，全球首款 200Gb/s SerDes CPO，已開始出貨</li><li><strong>Quantum-X InfiniBand</strong>：Q3450-LD，144 port 800Gb/s IB，液冷設計，2026 Q1 商用</li><li><strong>NVIDIA 光子投資 $40 億</strong>：Coherent + Lumentum 各 $20 億，Corning $5 億，Ayar Labs $5 億</li><li><strong>黃仁勳</strong>：從銅到光的轉型是 AI 資料中心的「fundamental shift」</li><li><strong>出口管制更新</strong>：美國商務部要求先進 AI 晶片出口中國子公司需取得許可證</li></ul></li><li><strong>評估</strong>：NVIDIA CPO 從「展示」進入「出貨」，台灣光通訊供應鏈正式進入收割期。出口管制可能限制中國客戶，但非中系 CSP 需求強勁。 📎 來源：<a href="https://economictimes.indiatimes.com/tech/artificial-intelligence/nvidia-starts-shipping-tsmc-backed-cpo-switches-to-tackle-ai-data-centre-bottlenecks/articleshow/131500748.cms?from=mdr" target="_blank" rel="noreferrer">Economic Times</a>、<a href="https://www.taipeitimes.com/News/biz/archives/2026/06/04/2003858481" target="_blank" rel="noreferrer">Taipei Times</a>（TST 05:00）</li></ul><hr><h3 id="指標2️⃣-博通-broadcom-—-🟢-taurus-400g-lane-dsp-第三代-cpo-技術" tabindex="-1">指標2️⃣ 博通 Broadcom — 🟢 Taurus 400G/lane DSP + 第三代 CPO 技術 <a class="header-anchor" href="#指標2️⃣-博通-broadcom-—-🟢-taurus-400g-lane-dsp-第三代-cpo-技術" aria-label="Permalink to &quot;指標2️⃣ 博通 Broadcom — 🟢 Taurus 400G/lane DSP + 第三代 CPO 技術&quot;">​</a></h3><ul><li><strong>最新動態</strong>： <ul><li><strong>Taurus BCM83640</strong>：業界首款 400G/lane 光學 DSP，3nm PAM-4，支援 1.6T 收發器</li><li>2026 年底量產，為 3.2T 收發器鋪路</li><li><strong>第三代 CPO</strong>：200G/lane，Meta 已測試 100 萬 link hours 無中斷</li><li><strong>Q2 FY2026 財報</strong>（6/3 盤後）： <ul><li>營收 $22.2B（+48% YoY），AI 半導體 $10.8B（+143% YoY）</li><li>Q3 指引：營收 $29.4B，AI 半導體 $16.0B（+200% YoY）</li><li>FY2027 AI 半導體 &gt;$100B（重申）</li></ul></li><li><strong>市場反應</strong>：盤後股價下跌，因 Q3 AI 晶片銷售略低於最樂觀預期</li></ul></li><li><strong>評估</strong>：Broadcom 在 CPO/DSP 領域與 NVIDIA 形成雙雄格局，Taurus 400G/lane 是下一代 3.2T 的基礎。基本面強勁，但短線情緒承壓。 📎 來源：<a href="https://www.broadcom.com/blog/ofc-2026-broadcom-paves-the-path-for-the-200t-ai-era" target="_blank" rel="noreferrer">Broadcom Blog</a>、<a href="https://www.servethehome.com/broadcom-launches-taurus-bcm83640-a-3nm-400g-per-lane-optical-dsp/" target="_blank" rel="noreferrer">ServeTheHome</a>、<a href="https://www.investing.com/news/company-news/broadcom-reports-48-revenue-growth-in-fiscal-q2-raises-guidance-93CH-4725176" target="_blank" rel="noreferrer">Investing.com</a>（TST 05:00）</li></ul><hr><h3 id="指標3️⃣-台積電-tsmc-—-🟢-coupe-量產-ceo-警告供不應求「非常久」" tabindex="-1">指標3️⃣ 台積電 TSMC — 🟢 COUPE 量產 + CEO 警告供不應求「非常久」 <a class="header-anchor" href="#指標3️⃣-台積電-tsmc-—-🟢-coupe-量產-ceo-警告供不應求「非常久」" aria-label="Permalink to &quot;指標3️⃣ 台積電 TSMC — 🟢 COUPE 量產 + CEO 警告供不應求「非常久」&quot;">​</a></h3><ul><li><strong>最新動態</strong>： <ul><li><strong>COUPE 平台</strong>：Compact Universal Photonic Engine，3D SoIC 封裝，每光引擎 1.6Tbps</li><li>2026 年量產，NVIDIA + Broadcom 為首批客戶</li><li><strong>CEO C.C. Wei 股東會</strong>（6/4）： <ul><li>AI 晶片供不應求將持續「非常久」，先進節點產能缺口約 3 倍</li><li>3nm 有 15% 漲價空間（H2 2026），2027 可能再漲</li><li>美國亞利桑那廠完全滿足美國客戶需求需「非常久」</li></ul></li><li><strong>台股</strong>：台積電 6/5 收 2,365（-0.84%），受美股科技股拖累</li><li><strong>65nm 矽光子已量產</strong>，3D 堆疊技術展示 200Gbps 光信號調變</li></ul></li><li><strong>評估</strong>：TSMC COUPE 是 CPO 量產的關鍵基礎設施，CEO 的「供不應求」警告確認 AI 半導體需求結構性強勁。3nm 漲價若實現，將直接提升毛利率。 📎 來源：<a href="https://bits-chips.com/article/tsmc-pushes-silicon-photonics-platform-to-mass-production/" target="_blank" rel="noreferrer">Bits&amp;Chips</a>、<a href="https://www.trendforce.com/news/2026/04/01/news-silicon-photonics-race-intensifies-as-tsmc-targets-2026-coupe-production-samsung-eyes-2029-cpo-turnkey/" target="_blank" rel="noreferrer">TrendForce</a>、<a href="https://borecraft.com/2026/06/01/tsmcs-silicon-photonics-capacity-is-the-next-ai-bottleneck/" target="_blank" rel="noreferrer">Borecraft</a>（TST 05:00）</li></ul><hr><h3 id="指標4️⃣-csp-資本支出-—-🟢-四大-csp-合計-690b-720b-ai-基礎設施為主力" tabindex="-1">指標4️⃣ CSP 資本支出 — 🟢 四大 CSP 合計 $690B-$720B，AI 基礎設施為主力 <a class="header-anchor" href="#指標4️⃣-csp-資本支出-—-🟢-四大-csp-合計-690b-720b-ai-基礎設施為主力" aria-label="Permalink to &quot;指標4️⃣ CSP 資本支出 — 🟢 四大 CSP 合計 $690B-$720B，AI 基礎設施為主力&quot;">​</a></h3><ul><li><strong>2026 年資本支出預估</strong>： <ul><li>Microsoft：~$190B</li><li>Google（Alphabet）：$175B-$185B（部分報告指 $190B）</li><li>Amazon：~$200B（最大支出者）</li><li>Meta：$125B-$145B（上修自 $115B-$135B）</li><li><strong>合計</strong>：$690B-$720B，較 2025 年 +40%~50%</li></ul></li><li><strong>光纖供應短缺</strong>：全球嚴重短缺，預計持續至 2027</li><li><strong>光收發模組</strong>：2026 年出貨量 tripling，TrendForce 預測全球 AI 光收發市場 $260 億（+57% YoY）</li><li><strong>CPO 市場</strong>：IDTechEx 預測 2036 年超 $200 億，CAGR 37%（2026-2036）</li><li><strong>評估</strong>：CSP capex 擴張 + 光纖短缺 + CPO 量產 → 光通訊族群基本面極度強勁。 📎 來源：<a href="https://www.tomshardware.com/tech-industry/big-tech/big-techs-ai-spending-plans-reach-725-billion" target="_blank" rel="noreferrer">Tom&#39;s Hardware</a>、<a href="https://futurumgroup.com/insights/ai-capex-2026-the-690b-infrastructure-sprint/" target="_blank" rel="noreferrer">Futurum Group</a>（TST 05:00）</li></ul><hr><h2 id="🟡-台灣光通訊供應鏈" tabindex="-1">🟡 台灣光通訊供應鏈 <a class="header-anchor" href="#🟡-台灣光通訊供應鏈" aria-label="Permalink to &quot;🟡 台灣光通訊供應鏈&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">公司</th><th style="text-align:center;">股票</th><th style="text-align:left;">最新動態</th><th style="text-align:center;">評估</th></tr></thead><tbody><tr><td style="text-align:left;">聯亞</td><td style="text-align:center;">3081</td><td style="text-align:left;">無個股特定更新</td><td style="text-align:center;">⚪</td></tr><tr><td style="text-align:left;">光聖</td><td style="text-align:center;">6442</td><td style="text-align:left;">無個股特定更新</td><td style="text-align:center;">⚪</td></tr><tr><td style="text-align:left;">上詮</td><td style="text-align:center;">3363</td><td style="text-align:left;">無個股特定更新</td><td style="text-align:center;">⚪</td></tr><tr><td style="text-align:left;">智邦</td><td style="text-align:center;">2345</td><td style="text-align:left;">COMPUTEX 參展，AI networking 需求強勁</td><td style="text-align:center;">🟢</td></tr></tbody></table><blockquote><p>📌 COMPUTEX 圓滿落幕（152 國、111,312 買家），後續關注法說會與訂單消息。液冷正式成為 AI 伺服器標配。</p></blockquote><hr><h2 id="📊-產業趨勢摘要" tabindex="-1">📊 產業趨勢摘要 <a class="header-anchor" href="#📊-產業趨勢摘要" aria-label="Permalink to &quot;📊 產業趨勢摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">趨勢</th><th style="text-align:center;">狀態</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;">銅退光進</td><td style="text-align:center;">🟢 加速</td><td style="text-align:left;">NVIDIA Spectrum-X CPO 正式出貨</td></tr><tr><td style="text-align:left;">2026 商轉元年</td><td style="text-align:center;">🟢 確認</td><td style="text-align:left;">CPO 進入量產階段</td></tr><tr><td style="text-align:left;">光纖短缺</td><td style="text-align:center;">🔴 嚴峻</td><td style="text-align:left;">預計持續至 2027</td></tr><tr><td style="text-align:left;">AI capex 擴張</td><td style="text-align:center;">🟢 極強</td><td style="text-align:left;">四大 CSP 合計 $690B-$720B</td></tr><tr><td style="text-align:left;">供不應求</td><td style="text-align:center;">🟢 確認</td><td style="text-align:left;">TSMC CEO 警告先進節點缺口 3 倍</td></tr><tr><td style="text-align:left;">液冷標配</td><td style="text-align:center;">🟢 確認</td><td style="text-align:left;">COMPUTEX 傳達明確訊息</td></tr></tbody></table><hr><h2 id="📅-關鍵日期" tabindex="-1">📅 關鍵日期 <a class="header-anchor" href="#📅-關鍵日期" aria-label="Permalink to &quot;📅 關鍵日期&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;">日期</th><th style="text-align:left;">事件</th><th style="text-align:center;">重要性</th></tr></thead><tbody><tr><td style="text-align:center;">6/5</td><td style="text-align:left;">COMPUTEX 圓滿落幕</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">6/12</td><td style="text-align:left;">NVIDIA GTC 後續效應</td><td style="text-align:center;">⭐⭐⭐</td></tr><tr><td style="text-align:center;">6 月中</td><td style="text-align:left;">台灣光通訊族群法說會季</td><td style="text-align:center;">⭐⭐⭐⭐</td></tr><tr><td style="text-align:center;">2026 H2</td><td style="text-align:left;">CPO 量產時程</td><td style="text-align:center;">⭐⭐⭐⭐⭐</td></tr></tbody></table><hr><h2 id="📚-資料來源" tabindex="-1">📚 資料來源 <a class="header-anchor" href="#📚-資料來源" aria-label="Permalink to &quot;📚 資料來源&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>來源</th><th style="text-align:center;">查詢時間 (TST)</th><th>數據</th></tr></thead><tbody><tr><td>1</td><td><a href="https://economictimes.indiatimes.com/tech/artificial-intelligence/nvidia-starts-shipping-tsmc-backed-cpo-switches-to-tackle-ai-data-centre-bottlenecks/articleshow/131500748.cms?from=mdr" target="_blank" rel="noreferrer">Economic Times</a></td><td style="text-align:center;">05:00</td><td>NVIDIA CPO 出貨</td></tr><tr><td>2</td><td><a href="https://www.broadcom.com/blog/ofc-2026-broadcom-paves-the-path-for-the-200t-ai-era" target="_blank" rel="noreferrer">Broadcom Blog</a></td><td style="text-align:center;">05:00</td><td>Taurus + CPO</td></tr><tr><td>3</td><td><a href="https://bits-chips.com/article/tsmc-pushes-silicon-photonics-platform-to-mass-production/" target="_blank" rel="noreferrer">Bits&amp;Chips</a></td><td style="text-align:center;">05:00</td><td>TSMC COUPE</td></tr><tr><td>4</td><td><a href="https://www.tomshardware.com/tech-industry/big-tech/big-techs-ai-spending-plans-reach-725-billion" target="_blank" rel="noreferrer">Tom&#39;s Hardware</a></td><td style="text-align:center;">05:00</td><td>CSP capex</td></tr><tr><td>5</td><td><a href="https://www.trendforce.com/news/2026/04/01/news-silicon-photonics-race-intensifies-as-tsmc-targets-2026-coupe-production-samsung-eyes-2029-cpo-turnkey/" target="_blank" rel="noreferrer">TrendForce</a></td><td style="text-align:center;">05:00</td><td>CPO 市場預測</td></tr></tbody></table>',28)])])}const p=e(n,[["render",i]]);export{m as __pageData,p as default};
